import styled, { css } from "styled-components";

import { ClickableIcon } from "../shared/clickable-icon";
import { ImagePlaceholder } from "../shared/image-placeholder";
import type { InsetStyleProps } from "../shared/types";
import { Typography } from "../typography";
import {
    V3_Border,
    V3_Colour,
    V3_MediaQuery,
    V3_Radius,
    V3_Shadow,
    V3_Spacing,
} from "../v3_theme";
import { StatefulImage } from "./stateful-image";

// =============================================================================
// STYLE INTERFACES
// =============================================================================
interface ArrowButtonStyleProps extends InsetStyleProps {
    $position: "left" | "right";
}

interface ThumbnailItemStyleProps {
    $active?: boolean;
}

// =============================================================================
// STYLING
// =============================================================================
const IconButton = styled(ClickableIcon)`
    padding: 0;
    border-radius: 100%;
    background: ${V3_Colour["bg"]};
    color: ${V3_Colour["icon-primary"]};
    height: 2.5rem;
    width: 2.5rem;
    box-shadow: ${V3_Shadow["md-strong"]};

    svg {
        height: 1.5rem;
        width: 1.5rem;
    }
`;

export const CloseButton = styled(IconButton)<InsetStyleProps>`
    position: absolute;
    top: ${(props) =>
        css`calc(${V3_Spacing["spacing-48"]} + ${props.$insetTop || 0}px)`};
    right: ${(props) =>
        css`calc(${V3_Spacing["spacing-48"]} + ${props.$insetRight || 0}px)`};
    z-index: 5;

    ${V3_MediaQuery.MaxWidth.sm} {
        top: ${(props) =>
            css`calc(${V3_Spacing["spacing-20"]} + ${props.$insetTop || 0}px)`};
        right: ${(props) =>
            css`calc(${V3_Spacing["spacing-20"]} + ${
                props.$insetRight || 0
            }px)`};
    }
`;

export const MagnifierButton = styled(IconButton)<InsetStyleProps>`
    position: absolute;
    top: ${(props) =>
        css`calc(${V3_Spacing["spacing-48"]} + ${props.$insetTop || 0}px)`};
    right: ${
        (props) =>
            css`calc(2.5rem + ${V3_Spacing["spacing-48"]} + ${
                V3_Spacing["spacing-16"]
            } + ${props.$insetRight || 0}px)` // close button + space from screen + gap between buttons
    };

    z-index: 5;

    ${V3_MediaQuery.MaxWidth.sm} {
        top: ${(props) =>
            css`calc(${V3_Spacing["spacing-20"]} + ${props.$insetTop || 0}px)`};
        right: ${
            (props) =>
                css`calc(2.5rem + ${V3_Spacing["spacing-20"]} + ${
                    V3_Spacing["spacing-16"]
                } + ${props.$insetRight || 0}px)` // close button + space from screen + gap between buttons
        };
    }
`;

export const ArrowButton = styled(IconButton)<ArrowButtonStyleProps>`
    z-index: 4;
    position: absolute;
    top: 50%;
    transform: translateY(-50%);

    ${(props) =>
        props.$position === "left" &&
        css`
            left: calc(
                ${V3_Spacing["spacing-48"]} + ${props.$insetLeft || 0}px
            );
            ${V3_MediaQuery.MaxWidth.sm} {
                left: calc(
                    ${V3_Spacing["spacing-20"]} + ${props.$insetLeft || 0}px
                );
            }
        `}

    ${(props) =>
        props.$position === "right" &&
        css`
            right: calc(
                ${V3_Spacing["spacing-48"]} + ${props.$insetRight || 0}px
            );
            ${V3_MediaQuery.MaxWidth.sm} {
                right: calc(
                    ${V3_Spacing["spacing-20"]} + ${props.$insetRight || 0}px
                );
            }
        `}
`;

export const ImageGalleryContainer = styled.div`
    display: flex;
    flex-direction: column;
    width: 100%;
    height: 100%;
`;

export const ImageGalleryWrapper = styled.div`
    user-select: none;
    position: relative;
    display: block;
    overflow: hidden;
    width: 100%;
    height: 100%;
`;

export const ImageGallerySwipe = styled.div`
    display: block;
    user-select: none;
    height: 100%;
    overflow: hidden;
    touch-action: pan-y;
`;

export const ImageGallerySlides = styled.div`
    display: flex;
    transition: all 450ms ease-out 0s;
    position: relative;
    text-align: center;
    user-select: none;
    width: 100%;
    height: 100%;
`;

export const ImageGallerySlide = styled.div`
    flex: 0 0 100%;
    box-sizing: border-box;
    display: flex;
    justify-content: center;
    align-items: center;
    .react-transform-wrapper {
        height: 100%;
        width: 100%;
    }
    .react-transform-component {
        height: 100%;
        width: 100%;
    }
`;

export const SlideImage = styled(StatefulImage)`
    height: 100%;
    width: 100%;
    border-radius: ${V3_Radius["none"]};
`;

export const SlidePlaceholderImage = styled(ImagePlaceholder)`
    width: 60vw;
    height: auto;
    max-height: 100%;
    border-radius: ${V3_Radius["none"]};
    aspect-ratio: 4 / 3;
`;

export const BoxChip = styled.div`
    display: flex;
    justify-content: center;
    padding: ${V3_Spacing["spacing-16"]};
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    margin-left: auto;
    margin-right: auto;
    z-index: 3;
`;

export const Chip = styled(Typography.BodyXS)`
    display: inline-flex;
    padding: ${V3_Spacing["spacing-4"]} ${V3_Spacing["spacing-16"]};
    justify-content: center;
    align-items: center;
    border-radius: ${V3_Radius["full"]};
    background-color: ${V3_Colour["bg"]};
    text-align: center;
`;

// -----------------------------------------------------------------------------
// THUMBNAIL STYLING
// -----------------------------------------------------------------------------

export const ThumbnailContainer = styled.div<InsetStyleProps>`
    flex-shrink: 0;
    display: flex;
    overflow: auto;
    background-color: ${V3_Colour["bg-inverse"]};
    padding: ${(props) =>
            css`
                ${V3_Spacing["spacing-24"]} ${V3_Spacing[
                    "spacing-16"
                ]} calc(${V3_Spacing["spacing-24"]} + ${props.$insetBottom ||
                0}px);
            `}
        ${V3_MediaQuery.MaxWidth.sm} {
        padding: ${(props) =>
            css`
                ${V3_Spacing["spacing-16"]} ${V3_Spacing[
                    "spacing-20"
                ]} calc(${V3_Spacing["spacing-16"]} + ${props.$insetBottom ||
                0}px);
            `};
    }
`;

export const ThumbnailWrapper = styled.div`
    box-sizing: border-box;
    display: flex;
    align-items: center;
    gap: ${V3_Spacing["spacing-16"]};
    justify-content: center;
    margin-left: auto;
    margin-right: auto;
`;

export const ThumbnailItemContainer = styled.div`
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100px;
    width: 100px;

    ${V3_MediaQuery.MaxWidth.sm} {
        height: 64px;
        width: 64px;
    }
`;

export const ThumbnailItem = styled.div<ThumbnailItemStyleProps>`
    cursor: pointer;
    background-color: ${V3_Colour["bg-inverse"]};
    border-radius: ${V3_Radius["md"]};
    border: ${V3_Border["solid"]} transparent;
    box-sizing: content-box;

    flex-shrink: 0;
    overflow: hidden;
    display: flex;
    align-items: center;
    justify-content: center;
    height: 92px;
    width: 92px;

    ${V3_MediaQuery.MaxWidth.sm} {
        height: 60px;
        width: 60px;
    }

    ${(props) =>
        props.$active
            ? css`
                  border-width: ${V3_Border["width-040"]};
                  border-color: ${V3_Colour["border-selected"]};

                  ${V3_MediaQuery.MaxWidth.sm} {
                      border-width: ${V3_Border["width-020"]};
                  }

                  &:hover {
                      border-color: ${V3_Colour["border-selected-hover"]};
                  }
              `
            : css`
                  border-width: ${V3_Border["width-010"]};

                  &:hover {
                      border-color: ${V3_Colour["border-hover"]};
                  }
              `};
`;

export const ThumbnailImage = styled(StatefulImage)`
    height: 100%;
    width: 100%;
`;
